import{_ as t,o as e,c as r,ai as l}from"./chunks/framework.CzqNhXfh.js";const p=JSON.parse('{"title":"分支切割算法","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/branch-and-cut.md","filePath":"or-opt/branch-and-cut.md","lastUpdated":1776761342000}'),o={name:"or-opt/branch-and-cut.md"};function i(h,a,d,n,s,u){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="分支切割算法" tabindex="-1">分支切割算法 <a class="header-anchor" href="#分支切割算法" aria-label="Permalink to &quot;分支切割算法&quot;">​</a></h1><p>分支切割算法（Branch and Cut）是在分支定界算法基础上的改进算法。</p><h2 id="有效不等式与凸包" tabindex="-1">有效不等式与凸包 <a class="header-anchor" href="#有效不等式与凸包" aria-label="Permalink to &quot;有效不等式与凸包&quot;">​</a></h2><h3 id="问题描述" tabindex="-1">问题描述 <a class="header-anchor" href="#问题描述" aria-label="Permalink to &quot;问题描述&quot;">​</a></h3><p>首先考虑整数规划（IP）问题：</p><p>$$ IP \\quad \\max{c^T x : x \\in X} $$</p><p>其中，$X = {x : Ax \\leq b, x \\in \\mathbb{Z}_+^n}$ 表示该整数规划的可行域。</p><p>这里的写法是为了简略，省去繁琐的约束表达式，直接用 $X$ 表示该整数规划的可行域。而 $x \\in X$ 则是该可行域内的任意可行解。</p><h3 id="凸包定理-wolsey-1998" tabindex="-1">凸包定理（Wolsey, 1998） <a class="header-anchor" href="#凸包定理-wolsey-1998" aria-label="Permalink to &quot;凸包定理（Wolsey, 1998）&quot;">​</a></h3><p><strong>定理</strong>：IP 的所有整数可行解构成的可行域（离散的点）的凸包 $Conv(X) = {x : \\tilde{A}x \\leq \\tilde{b}, x \\geq 0}$ 是一个多面体。</p><p>其中，$Conv(X)$ 表示可行域 $X$ 的凸包（Convex Hull）。$\\tilde{A}x \\leq \\tilde{b}$ 精确地刻画出了可行域 $X$ 的凸包。</p><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to &quot;核心思想&quot;">​</a></h3><p>对于 IP 来讲，最优整数解一定在凸包中，因此在可行域内搜索最优解和在凸包内搜索最优解是等价的。根据这一点，我们可以将原问题重新建模成下面的线性规划：</p><p>$$ LP \\quad \\max{c^T x : \\tilde{A}x \\leq \\tilde{b}, x \\geq 0} $$</p><p>并且，对于所有的 $c$（也就是任意线性目标函数），LP 的最优极点就是 IP 的最优解。对于混合整数规划，该结论也成立。</p><h3 id="逼近凸包" tabindex="-1">逼近凸包 <a class="header-anchor" href="#逼近凸包" aria-label="Permalink to &quot;逼近凸包&quot;">​</a></h3><p>既然凸包对应的 LP 的最优极点就是 IP 的最优解，那我们只要找到 IP 的所有可行解的凸包，然后求解一个线性规划就可以完美地解决整数规划了。</p><p>对于最小生成树问题和指派问题来讲，凸包的刻画比较容易，这两类问题都不是 NP-hard 问题。但是对于 NP-hard 问题，找到它们的凸包的清晰刻画基本是不可能的。因此，只能采取一些办法去逼近它们的凸包。</p><p><strong>有效不等式（Valid Inequality）以及割平面</strong>，就是来完成这一任务的。它们的功能就是不断地切割可行域，不断地逼近凸包。</p><h2 id="算法思想" tabindex="-1">算法思想 <a class="header-anchor" href="#算法思想" aria-label="Permalink to &quot;算法思想&quot;">​</a></h2><p>分支切割算法就是在分支定界算法的基础上，在分支的同时，根据节点的解的信息以及其他有用信息（例如一些问题特性等），给节点对应的子问题构造并添加割平面（Cutting plane），在缩小子问题的可行域的同时，又不排除任何可行整数解，从而更快地找到最优解的一种高效的算法。</p><p>也正是由于加入的割平面没有割去任何可行整数解，所以分支切割算法也是可以保证最优性的。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="割平面-cutting-plane" tabindex="-1">割平面（Cutting Plane） <a class="header-anchor" href="#割平面-cutting-plane" aria-label="Permalink to &quot;割平面（Cutting Plane）&quot;">​</a></h3><p>割平面是一种线性不等式约束，用于切割掉当前线性松弛解中的非整数部分，同时保留所有可行的整数解。</p><h3 id="割平面的特点" tabindex="-1">割平面的特点 <a class="header-anchor" href="#割平面的特点" aria-label="Permalink to &quot;割平面的特点&quot;">​</a></h3><ul><li>缩小可行域范围，提高求解效率</li><li>不割除任何可行整数解，保证最优性</li><li>迭代添加，逐步逼近整数最优解</li></ul><h2 id="算法流程" tabindex="-1">算法流程 <a class="header-anchor" href="#算法流程" aria-label="Permalink to &quot;算法流程&quot;">​</a></h2><p>分支切割算法结合了分支定界和割平面两种技术：</p><h3 id="_1-求解线性松弛" tabindex="-1">1. 求解线性松弛 <a class="header-anchor" href="#_1-求解线性松弛" aria-label="Permalink to &quot;1. 求解线性松弛&quot;">​</a></h3><p>求得当前节点的线性松弛最优解。</p><h3 id="_2-判断是否满足整数条件" tabindex="-1">2. 判断是否满足整数条件 <a class="header-anchor" href="#_2-判断是否满足整数条件" aria-label="Permalink to &quot;2. 判断是否满足整数条件&quot;">​</a></h3><p>如果解满足整数条件，更新全局最优解；如果不满足，继续下一步。</p><h3 id="_3-尝试添加割平面" tabindex="-1">3. 尝试添加割平面 <a class="header-anchor" href="#_3-尝试添加割平面" aria-label="Permalink to &quot;3. 尝试添加割平面&quot;">​</a></h3><p>根据当前解的信息，尝试构造有效的割平面：</p><ul><li>如果找到有效割平面，添加后重新求解线性松弛</li><li>如果没有找到有效割平面，进行分支操作</li></ul><h3 id="_4-分支或继续切割" tabindex="-1">4. 分支或继续切割 <a class="header-anchor" href="#_4-分支或继续切割" aria-label="Permalink to &quot;4. 分支或继续切割&quot;">​</a></h3><ul><li><strong>切割</strong>：添加割平面后，可行域缩小，继续求解</li><li><strong>分支</strong>：当无法找到有效割平面时，按照分支定界的方法进行分支</li></ul><h3 id="_5-迭代直至收敛" tabindex="-1">5. 迭代直至收敛 <a class="header-anchor" href="#_5-迭代直至收敛" aria-label="Permalink to &quot;5. 迭代直至收敛&quot;">​</a></h3><p>重复上述过程，直到找到最优整数解或证明无解。</p><h2 id="与分支定界的区别" tabindex="-1">与分支定界的区别 <a class="header-anchor" href="#与分支定界的区别" aria-label="Permalink to &quot;与分支定界的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>分支定界</th><th>分支切割</th></tr></thead><tbody><tr><td>核心操作</td><td>分支 + 定界</td><td>分支 + 切割 + 定界</td></tr><tr><td>求解效率</td><td>依赖于分支策略</td><td>割平面加速收敛</td></tr><tr><td>实现复杂度</td><td>相对简单</td><td>需要设计有效割平面</td></tr><tr><td>最优性保证</td><td>是</td><td>是（割平面不割除整数解）</td></tr></tbody></table><h2 id="常用割平面类型" tabindex="-1">常用割平面类型 <a class="header-anchor" href="#常用割平面类型" aria-label="Permalink to &quot;常用割平面类型&quot;">​</a></h2><h3 id="gomory-割平面" tabindex="-1">Gomory 割平面 <a class="header-anchor" href="#gomory-割平面" aria-label="Permalink to &quot;Gomory 割平面&quot;">​</a></h3><p>最经典的割平面方法，从单纯形表最后一行构造，保证能切割掉当前非整数解。</p><h3 id="覆盖割平面-cover-cuts" tabindex="-1">覆盖割平面（Cover Cuts） <a class="header-anchor" href="#覆盖割平面-cover-cuts" aria-label="Permalink to &quot;覆盖割平面（Cover Cuts）&quot;">​</a></h3><p>针对背包约束等特殊结构设计的割平面。</p><h3 id="流割平面-flow-cuts" tabindex="-1">流割平面（Flow Cuts） <a class="header-anchor" href="#流割平面-flow-cuts" aria-label="Permalink to &quot;流割平面（Flow Cuts）&quot;">​</a></h3><p>针对网络流问题设计的特殊割平面。</p><h2 id="算法优势" tabindex="-1">算法优势 <a class="header-anchor" href="#算法优势" aria-label="Permalink to &quot;算法优势&quot;">​</a></h2><p>分支切割算法结合了两种技术的优点：</p><ul><li><strong>割平面</strong>快速收紧松弛界，减少分支节点数</li><li><strong>分支定界</strong>保证找到全局最优解</li></ul><p>这种组合使得分支切割算法成为求解混合整数规划（MIP）问题的最主流方法，被广泛应用于商业求解器如 CPLEX、Gurobi 中。</p>',53)])])}const b=t(o,[["render",i]]);export{p as __pageData,b as default};
